from flask import Flask, request, jsonify
import jwt
import datetime
import time

app = Flask(__name__)

SECRET_KEY = "super-gizli-anahtar-kimse-bilemez"
ALGORITHM = "HS256"

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username', None)
    password = request.json.get('password', None)

    if username == 'testuser' and password == 'testpass':
        expiration_time = datetime.datetime.utcnow() + datetime.timedelta(minutes=1)

        payload = {
            'user_id': 123,
            'username': username,
            'exp': expiration_time,
            'iat': datetime.datetime.utcnow()
        }

        token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)

        return jsonify({'token': token})

    return jsonify({'message': 'Geçersiz kimlik bilgileri'}), 401

@app.route('/protected', methods=['GET'])
def protected_route():
    auth_header = request.headers.get('Authorization')

    if not auth_header:
        return jsonify({'message': 'Authorization başlığı eksik!'}), 401

    try:
        token = auth_header.split(" ")[1]
    except IndexError:
        return jsonify({'message': 'Token formatı geçersiz! "Bearer <token>" bekleniyor'}), 401

    try:
        decoded_token = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])

        return jsonify({
            'message': 'Token geçerli!',
            'user_id': decoded_token.get('user_id'),
            'username': decoded_token.get('username'),
            'exp_utc': decoded_token.get('exp'),
            'iat_utc': decoded_token.get('iat')
        })
    except jwt.ExpiredSignatureError:
        return jsonify({'message': 'Token süresi dolmuş!'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'message': 'Geçersiz token!'}), 401
    except Exception as e:
        return jsonify({'message': f'Bir hata oluştu: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(debug=True)
